Author: Bram Wasti <bwasti@fb.com>
Date:   Thu Sep 22 23:29:38 2022 -0400

    check in missing stats file
---
 shumai/tensor/stats.ts | 24 ++++++++++++++++++++++++
 1 file changed, 24 insertions(+)

diff --git a/shumai/tensor/stats.ts b/shumai/tensor/stats.ts
new file mode 100644
index 0000000..a96c9c6
--- /dev/null
+++ b/shumai/tensor/stats.ts
@@ -0,0 +1,24 @@
+/** @private */
+export const getStack = () => {
+  const e = new Error('')
+  return e.stack.split('\n').slice(1)
+}
+
+/** @private */
+export function collectStats(tensors) {
+  const stats = {}
+  for (const t of tensors) {
+    if (!t.stats) {
+      continue
+    }
+    for (const key of Object.keys(t.stats)) {
+      if (key in stats) {
+        stats[key].time += t.stats[key].time
+        stats[key].bytes += t.stats[key].bytes
+      } else {
+        stats[key] = t.stats[key]
+      }
+    }
+  }
+  return stats
+}

