+      for (let i = 0; i < t.elements; i++) {
+        expect[i] = 1 / (1 + Math.exp(-1.0))
+      }
+      expectArraysClose(r.toFloat32Array(), expect)
+    })
+  */
+
+  it('propagates NaNs', () => {
+    const values = [3, NaN]
